using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummaryService
{
    // Common English stop words excluded from scoring.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","could",
        "should","may","might","shall","can","to","of","in","for","on","with",
        "at","by","from","as","into","through","during","before","after","it",
        "its","this","that","these","those","i","you","he","she","we","they",
        "me","him","her","us","them","my","your","his","our","their","not","no"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordExtractor();

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count <= maxSentences)
            return text.Trim();

        // Build word frequency map (excluding stop words).
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var match in WordExtractor().EnumerateMatches(sentence))
            {
                var word = sentence.AsSpan(match.Index, match.Length).ToString();
                if (!StopWords.Contains(word))
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies.
        var scored = sentences
            .Select((sentence, index) =>
            {
                var score = 0;
                foreach (var match in WordExtractor().EnumerateMatches(sentence))
                {
                    var word = sentence.AsSpan(match.Index, match.Length).ToString();
                    if (wordFrequency.TryGetValue(word, out var freq))
                        score += freq;
                }
                return (Sentence: sentence, Index: index, Score: score);
            })
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummaryController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

