+                var score = 0;
+                foreach (var match in WordExtractor().EnumerateMatches(sentence))
+                {
+                    var word = sentence.AsSpan(match.Index, match.Length).ToString();
+                    if (wordFrequency.TryGetValue(word, out var freq))
+                        score += freq;
+                }
+                return (Sentence: sentence, Index: index, Score: score);
+            })
+            .OrderByDescending(x => x.Score)
+            .Take(maxSentences)
+            .OrderBy(x => x.Index) // preserve original order
+            .Select(x => x.Sentence);
+
+        return string.Join(" ", scored);
+    }
+}
